import Link from "next/link";
import type { ComponentPropsWithoutRef, ElementType, ReactNode } from "react";

function cx(...values: Array<string | false | null | undefined>) {
  return values.filter(Boolean).join(" ");
}

type SurfaceTone = "hero" | "panel" | "card" | "shell" | "inset";

const surfaceToneClasses: Record<SurfaceTone, string> = {
  hero: "hero-card ui-surface ui-surface-hero",
  panel: "panel-card ui-surface ui-surface-panel",
  card: "feature-card ui-surface ui-surface-card",
  shell: "vault-frame ui-surface ui-surface-shell",
  inset: "public-note-metadata ui-surface ui-surface-inset"
};

type SurfaceProps<T extends ElementType> = {
  as?: T;
  tone?: SurfaceTone;
  children: ReactNode;
  className?: string;
} & Omit<ComponentPropsWithoutRef<T>, "as" | "children" | "className">;

export function Surface<T extends ElementType = "section">({
  as,
  tone = "panel",
  children,
  className,
  ...props
}: SurfaceProps<T>) {
  const Component = as ?? "section";

  return (
    <Component className={cx(surfaceToneClasses[tone], className)} {...props}>
      {children}
    </Component>
  );
}

type SectionHeadingProps = {
  title: ReactNode;
  meta?: ReactNode;
  className?: string;
};

export function SectionHeading({ title, meta, className }: SectionHeadingProps) {
  return (
    <div className={cx("section-heading ui-section-heading", className)}>
      <strong>{title}</strong>
      {meta ? <span className="section-meta">{meta}</span> : null}
    </div>
  );
}

type MetadataRowProps = ComponentPropsWithoutRef<"div"> & {
  leading?: boolean;
};

export function MetadataRow({ children, className, leading = false, ...props }: MetadataRowProps) {
  return (
    <div className={cx("note-meta ui-metadata-row", leading && "note-meta-leading", className)} {...props}>
      {children}
    </div>
  );
}

type TagListProps = ComponentPropsWithoutRef<"div">;

export function TagList({ children, className, ...props }: TagListProps) {
  return (
    <div className={cx("tag-list ui-tag-list", className)} {...props}>
      {children}
    </div>
  );
}

type TagChipProps = ComponentPropsWithoutRef<"span"> & {
  muted?: boolean;
};

export function TagChip({ children, className, muted = false, ...props }: TagChipProps) {
  return (
    <span className={cx("tag-pill ui-tag", muted && "tag-pill-muted ui-tag-muted", className)} {...props}>
      {children}
    </span>
  );
}

type ButtonVariant = "primary" | "ghost";

type ButtonProps = ComponentPropsWithoutRef<"button"> & {
  variant?: ButtonVariant;
};

export function Button({ children, className, variant = "primary", ...props }: ButtonProps) {
  return (
    <button className={cx(`${variant}-button`, "ui-button", `ui-button-${variant}`, className)} {...props}>
      {children}
    </button>
  );
}

type ButtonLinkProps = Omit<ComponentPropsWithoutRef<typeof Link>, "href"> & {
  href: string;
  variant?: ButtonVariant;
};

export function ButtonLink({ children, className, href, variant = "primary", ...props }: ButtonLinkProps) {
  return (
    <Link
      className={cx(`${variant}-button`, "ui-button", `ui-button-${variant}`, className)}
      href={href as unknown as ComponentPropsWithoutRef<typeof Link>["href"]}
      {...props}
    >
      {children}
    </Link>
  );
}

type DetailBlockProps = ComponentPropsWithoutRef<"div"> & {
  title: ReactNode;
};

export function DetailBlock({ children, className, title, ...props }: DetailBlockProps) {
  return (
    <div className={cx("detail-block ui-detail-block", className)} {...props}>
      <strong>{title}</strong>
      {children}
    </div>
  );
}

import "server-only";

import { requestEnrichment, retryEnrichment } from "@/features/enrichment/service";
import { notesRepo } from "@/features/notes/repo";
import { createNoteExcerpt } from "@/features/notes/markdown";
import type { NoteDraftInput } from "@/features/notes/types";
import { createUniqueNoteSlug } from "@/features/notes/slug";

function normalizeTitle(title: string) {
  const trimmedTitle = title.trim();

  return trimmedTitle || "Untitled note";
}

export async function listOwnerNotes(ownerId: string) {
  return notesRepo.listForOwner(ownerId);
}

export async function listPublishedNotes() {
  const notes = await notesRepo.listPublished();

  return notes.filter((note): note is typeof note & { publishedAt: Date } => note.publishedAt !== null);
}

export async function getOwnerNoteForEditor(ownerId: string, id: string) {
  return notesRepo.findByIdForOwner(ownerId, id);
}

export async function getPublishedNoteBySlug(slug: string) {
  const note = await notesRepo.findPublishedBySlug(slug);

  if (!note?.publishedAt) {
    return null;
  }

  return note;
}

export async function createDraftNote(ownerId: string, input: NoteDraftInput) {
  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  return notesRepo.create(ownerId, {
    title,
    slug: createUniqueNoteSlug(title, existingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title)
  });
}

export async function updateDraftNote(ownerId: string, id: string, input: NoteDraftInput) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  const title = normalizeTitle(input.title);
  const markdown = input.markdown;
  const existingSlugs = await notesRepo.listSlugsForOwner(ownerId);
  const siblingSlugs = existingSlugs.filter((slug) => slug !== existingNote.slug);
  return notesRepo.update(id, {
    title,
    slug: createUniqueNoteSlug(title, siblingSlugs),
    markdown,
    excerpt: createNoteExcerpt(markdown, title)
  });
}

export async function publishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, true);
}

export async function unpublishNote(ownerId: string, id: string) {
  const existingNote = await notesRepo.findByIdForOwner(ownerId, id);

  if (!existingNote) {
    return null;
  }

  if (!existingNote.isPublished) {
    return existingNote;
  }

  return notesRepo.updatePublication(id, false);
}

export async function retryNoteEnrichment(ownerId: string, id: string) {
  const note = await notesRepo.findByIdForOwner(ownerId, id);

  if (!note) {
    return null;
  }

  return retryEnrichment(notesRepo, id, note);
}

export async function startNoteEnrichment(id: string) {
  return requestEnrichment(notesRepo, id);
}

